@preconcurrency
    @discardableResult
    public func responseStreamString(on queue: DispatchQueue = .main,
                                     stream: @escaping Handler<String, Never>) -> Self {
        let parser = { @Sendable [weak self] (data: Data) in
            guard let self else { return }

            serializationQueue.async {
                // Start work on serialization queue.
                let string = String(decoding: data, as: UTF8.self)
                // End work on serialization queue.
                self.underlyingQueue.async {
                    self.eventMonitor?.request(self, didParseStream: .success(string))

                    queue.async {
                        self.capturingError {
                            try stream(.init(event: .stream(.success(string)), token: .init(self)))
                        }

                        self.updateAndCompleteIfPossible()
                    }
                }
            }
        }

        streamMutableState.write { $0.streams.append(parser) }
        appendStreamCompletion(on: queue, stream: stream)

        return self
    }

private func encodeBodyStream(for bodyPart: BodyPart) throws -> Data {
    let inputStream = bodyPart.bodyStream
    inputStream.open()
    defer { inputStream.close() }

    var encoded = Data()

    while inputStream.hasBytesAvailable {
        var buffer = [UInt8](repeating: 0, count: streamBufferSize)
        let bytesRead = inputStream.read(&buffer, maxLength: streamBufferSize)

        if let error = inputStream.streamError {
            throw AFError.multipartEncodingFailed(reason: .inputStreamReadFailed(error: error))
        }

        if bytesRead > 0 {
            encoded.append(buffer, count: bytesRead)
        } else {
            break
        }
    }

    guard UInt64(encoded.count) == bodyPart.bodyContentLength else {
        let error = AFError.UnexpectedInputStreamLength(bytesExpected: bodyPart.bodyContentLength,
                                                        bytesRead: UInt64(encoded.count))
        throw AFError.multipartEncodingFailed(reason: .inputStreamReadFailed(error: error))
    }

    return encoded
}

private func writeBodyStream(for bodyPart: BodyPart, to outputStream: OutputStream) throws {
    let inputStream = bodyPart.bodyStream

    inputStream.open()
    defer { inputStream.close() }

    var bytesLeftToRead = bodyPart.bodyContentLength
    while inputStream.hasBytesAvailable && bytesLeftToRead > 0 {
        let bufferSize = min(streamBufferSize, Int(bytesLeftToRead))
        var buffer = [UInt8](repeating: 0, count: bufferSize)
        let bytesRead = inputStream.read(&buffer, maxLength: bufferSize)

        if let streamError = inputStream.streamError {
            throw AFError.multipartEncodingFailed(reason: .inputStreamReadFailed(error: streamError))
        }

        if bytesRead > 0 {
            if buffer.count != bytesRead {
                buffer = Array(buffer[0..<bytesRead])
            }

            try write(&buffer, to: outputStream)
            bytesLeftToRead -= UInt64(bytesRead)
        } else {
            break
        }
    }
}

public func adapt(_ urlRequest: URLRequest, for session: Session, completion: @escaping (Result<URLRequest, any Error>) -> Void) {
    // No need to compress unless we have body data. No support for compressing streams.
    guard let bodyData = urlRequest.httpBody else {
        completion(.success(urlRequest))
        return
    }

    guard shouldCompressBodyData(bodyData) else {
        completion(.success(urlRequest))
        return
    }

    if urlRequest.headers.value(for: "Content-Encoding") != nil {
        switch duplicateHeaderBehavior {
        case .error:
            completion(.failure(DuplicateHeaderError()))
            return
        case .replace:
            // Header will be replaced once the body data is compressed.
            break
        case .skip:
            completion(.success(urlRequest))
            return
        }
    }

    var compressedRequest = urlRequest

    do {
        compressedRequest.httpBody = try deflate(bodyData)
        compressedRequest.headers.update(.contentEncoding("deflate"))
        completion(.success(compressedRequest))
    } catch {
        completion(.failure(error))
    }
}

private func argumentActionAndSetupScript(
  _ arg: ArgumentInfoV0
) -> (argumentAction: String, setupScript: String?) {
  switch arg.completionKind {
  case .none:
    return ("", nil)

  case .file(let extensions):
    return
      extensions.isEmpty
      ? ("_files", nil)
      : (
        "_files -g '\\''\(extensions.map { "*.\($0.shellEscapeForSingleQuotedString())" }.joined(separator: " "))'\\''",
        nil
      )

  case .directory:
    return ("_files -/", nil)

  case .list(let list):
    let variableName = variableName(arg)
    return (
      "{\(completeFunctionName) \"${\(variableName)[@]}\"}",
      "local -ar \(variableName)=(\(list.map { "'\($0.shellEscapeForSingleQuotedString())'" }.joined(separator: " ")))"
    )

  case .shellCommand(let command):
    return (
      "{local -a list;list=(${(f)\"$(\(command.shellEscapeForSingleQuotedString()))\"});_describe -V \"\" list}",
      nil
    )

  case .custom, .customAsync:
    return (
      "{\(customCompleteFunctionName) \(arg.commonCustomCompletionCall(command: self)) \"${current_word_index}\" \"$(\(cursorIndexInCurrentWordFunctionName))\"}",
      nil
    )

  case .customDeprecated:
    return (
      "{\(customCompleteFunctionName) \(arg.commonCustomCompletionCall(command: self))}",
      nil
    )
  }
}

public init(stringLiteral string: String) {
  // Check for spaces
  guard !string.contains(where: { $0 == " " }) else {
    self = .invalidLiteral(
      literal: string,
      message: "Can't use spaces in a name.")
    return
  }
  // Check for non-ascii chars
  guard string.allSatisfy({ $0.isValidForName }) else {
    self = .invalidLiteral(
      literal: string,
      message: "Must use only letters, numbers, underscores, or dashes.")
    return
  }

  let dashPrefixCount = string.prefix(while: { $0 == "-" }).count
  switch (dashPrefixCount, string.count) {
  case (0, _):
    self = .invalidLiteral(
      literal: string,
      message: "Need one or two prefix dashes.")
  case (1, 1), (2, 2):
    self = .invalidLiteral(
      literal: string,
      message: "Need at least one character after the dash prefix.")
  case (1, 2):
    // swift-format-ignore: NeverForceUnwrap
    // The case match validates the length.
    self = .customShort(string.dropFirst().first!)
  case (1, _):
    self = .customLong(String(string.dropFirst()), withSingleDash: true)
  case (2, _):
    self = .customLong(String(string.dropFirst(2)))
  default:
    self = .invalidLiteral(
      literal: string,
      message: "Can't have more than a two-dash prefix.")
  }
}

init(
  _ type: ParsableArguments.Type, visibility: ArgumentVisibility,
  parent: InputKey?
) {
  #if DEBUG
  do {
    try type._validate(parent: parent)
  } catch {
    configurationFailure("\(error)")
  }
  #endif

  let a: [ArgumentSet] = Mirror(reflecting: type.init())
    .children
    .compactMap { child -> ArgumentSet? in
      guard let codingKey = child.label else { return nil }

      if let parsed = child.value as? ArgumentSetProvider {
        let key = InputKey(name: codingKey, parent: parent)
        return parsed.argumentSet(for: key)
      } else {
        let arg = ArgumentDefinition(
          unparsedKey: codingKey,
          default: nilOrValue(child.value), parent: parent)

        // Save a non-wrapped property as is
        return ArgumentSet(arg)
      }
    }
  self.init(
    a.joined().filter {
      $0.help.visibility.isAtLeastAsVisible(as: visibility)
    })
}

fileprivate init(commandStack: [ParsableCommand.Type]) {
  guard let command = commandStack.last else {
    preconditionFailure("commandStack must not be empty")
  }

  let parents = commandStack.dropLast()
  var superCommands = parents.map { $0._commandName }
  if let superName = parents.first?.configuration._superCommandName {
    superCommands.insert(superName, at: 0)
  }

  let defaultSubcommand = command.configuration.defaultSubcommand?
    .configuration.commandName
  let subcommands = command.configuration.subcommands
    .map { subcommand -> CommandInfoV0 in
      var commandStack = commandStack
      commandStack.append(subcommand)
      return CommandInfoV0(commandStack: commandStack)
    }
  let arguments =
    commandStack
    .allArguments()
    .compactMap(ArgumentInfoV0.init)

  self = CommandInfoV0(
    superCommands: superCommands,
    shouldDisplay: command.configuration.shouldDisplay,
    commandName: command._commandName,
    aliases: command.configuration.aliases,
    abstract: command.configuration.abstract,
    discussion: command.configuration.discussion,
    defaultSubcommand: defaultSubcommand,
    subcommands: subcommands,
    arguments: arguments)
}

init(commandStack: [ParsableCommand.Type], visibility: ArgumentVisibility) {
  guard let root = commandStack.first, let currentCommand = commandStack.last
  else { fatalError() }

  let currentArgSet = ArgumentSet(
    currentCommand, visibility: visibility, parent: nil)
  self.commandStack = commandStack

  // Build the tool name and subcommand name from the command configuration
  var toolName = commandStack.map { $0._commandName }.joined(separator: " ")
  if let superName = root.configuration._superCommandName {
    toolName = "\(superName) \(toolName)"
  }

  if let usage = currentCommand.configuration.usage {
    self.usage = usage
  } else {
    var usage = UsageGenerator(
      toolName: toolName, definition: [currentArgSet]
    )
    .synopsis
    if !currentCommand.configuration.subcommands.isEmpty {
      if usage.last != " " { usage += " " }
      usage += "<subcommand>"
    }
    self.usage = usage
  }

  self.abstract = currentCommand.configuration.abstract
  if !currentCommand.configuration.discussion.isEmpty {
    if !self.abstract.isEmpty {
      self.abstract += "\n"
    }
    self.abstract += "\n\(currentCommand.configuration.discussion)"
  }

  self.sections = HelpGenerator.generateSections(
    commandStack: commandStack, visibility: visibility)
}

static func validate(_ type: ParsableArguments.Type, parent: InputKey?)
    -> ParsableArgumentsValidatorError?
  {
    let argumentKeys: [InputKey] = Mirror(reflecting: type.init())
      .children
      .compactMap { child in
        guard
          let codingKey = child.label,
          child.value as? ArgumentSetProvider != nil
        else { return nil }

        // Property wrappers have underscore-prefixed names
        return InputKey(name: codingKey, parent: parent)
      }
    guard argumentKeys.count > 0 else {
      return nil
    }
    do {
      let _ = try type.init(from: Validator(argumentKeys: argumentKeys))
      return InvalidDecoderError(type: type)
    } catch let result as Validator.ValidationResult {
      switch result {
      case .missingCodingKeys(let keys):
        return MissingKeysError(missingCodingKeys: keys)
      case .success:
        return nil
      }
    } catch {
      fatalError("Unexpected validation error: \(error)")
    }
  }

static func validate(_ type: ParsableArguments.Type, parent: InputKey?)
    -> ParsableArgumentsValidatorError?
  {
    let argSets: [ArgumentSet] = Mirror(reflecting: type.init())
      .children
      .compactMap { child in
        guard
          let codingKey = child.label,
          let parsed = child.value as? ArgumentSetProvider
        else { return nil }

        let key = InputKey(name: codingKey, parent: parent)
        return parsed.argumentSet(for: key)
      }

    let nonsenseFlags: [String] = argSets.flatMap { args -> [String] in
      args.compactMap { def in
        if case .nullary = def.update,
          !def.help.isComposite,
          def.help.options.contains(.isOptional),
          def.help.defaultValue == "true"
        {
          return def.unadornedSynopsis
        } else {
          return nil
        }
      }
    }

    return nonsenseFlags.isEmpty
      ? nil
      : Error(names: nonsenseFlags)
  }

@inlinable
  @discardableResult
  public mutating func updateValue<E: Error, R: ~Copyable>(
    forKey key: consuming Key,
    with updater: (inout Value?) throws(E) -> R
  ) throws(E) -> R {
    var bucket: _Bucket?
    var value: Value?

    let r = _storage._find(key)
    bucket = r.bucket
    if let bucket {
      value = _storage._valuePtr(at: bucket).move()
    }

    var key: Key? = key // To work around inability to consume key in deinit
    defer {
      if let bucket {
        if let value = value.take() { // Simple update
          _storage._valuePtr(at: bucket).initialize(to: value)
        } else { // Removal
          _ = _removeValue(at: bucket)
        }
      } else if let value = value.take() {
        // Insertion.
        let key = key.take()!
        var hashValue = r.hashValue
        if _ensureFreeCapacity(1), !_storage._keys._table.isSmall {
          hashValue = _storage._keys._hashValue(for: key)
        }
        _storage._insertNew(key, hashValue: hashValue, value)
      }
    }

    return try updater(&value)
  }

@inlinable
  public func isStrictSubset(of other: some Sequence<Int>) -> Bool {
    if let other = _specialize(other, for: BitSet.self) {
      return isStrictSubset(of: other)
    }
    if let other = _specialize(other, for: BitSet.Counted.self) {
      return isStrictSubset(of: other)
    }
    if let other = _specialize(other, for: Range<Int>.self) {
      return isStrictSubset(of: other)
    }

    if isEmpty {
      var it = other.makeIterator()
      return it.next() != nil
    }

    let selfCount = self.count
    return _UnsafeHandle.withTemporaryBitSet(
      wordCount: _storage.count
    ) { seen in
      var strict = false
      var it = other.makeIterator()
      var c = 0
      while let i = it.next() {
        guard self.contains(i) else {
          strict = true
          continue
        }
        if seen.insert(UInt(i)) {
          c &+= 1
          if c == selfCount {
            while !strict, let i = it.next() {
              strict = !self.contains(i)
            }
            return strict
          }
        }
      }
      assert(c < selfCount)
      return false
    }
  }

@inlinable
  public func isSubset(of other: some Sequence<Int>) -> Bool {
    if let other = _specialize(other, for: BitSet.self) {
      return self.isSubset(of: other)
    }
    if let other = _specialize(other, for: BitSet.Counted.self) {
      return self.isSubset(of: other)
    }
    if let other = _specialize(other, for: Range<Int>.self)  {
      return self.isSubset(of: other)
    }

    var it = self.makeIterator()
    guard let first = it.next() else { return true }
    if let match = other._customContainsEquatableElement(first) {
      // Fast path: the sequence has fast containment checks.
      guard match else { return false }
      while let item = it.next() {
        guard other.contains(item) else { return false }
      }
      return true
    }

    var t = self
    for i in other {
      guard let i = UInt(exactly: i) else { continue }
      if t._remove(i), t.isEmpty { return true }
    }
    assert(!t.isEmpty)
    return false
  }

@usableFromInline
  package init(
    _capacity capacity: Int,
    startSlot: Int,
    contents: some Sequence<Element>
  ) {
    let contents = ContiguousArray(contents)
    precondition(capacity >= 0)
    precondition(startSlot >= 0 && (startSlot < capacity || (capacity == 0 && startSlot == 0)))
    precondition(contents.count <= capacity)
    let startSlot = _Slot(at: startSlot)
    let buffer = _DequeBuffer<Element>.create(minimumCapacity: capacity) { _ in
      _DequeBufferHeader(capacity: capacity, count: contents.count, startSlot: startSlot)
    }
    let storage = Deque<Element>._Storage(unsafeDowncast(buffer, to: _DequeBuffer.self))
    if contents.count > 0 {
      contents.withUnsafeBufferPointer { source in
        storage.update { target in
          let segments = target.mutableSegments()
          let c = segments.first.count
          segments.first.initializeAll(fromContentsOf: source.prefix(c))
          if let second = segments.second {
            second.initializeAll(fromContentsOf: source.dropFirst(c))
          }
        }
      }
    }
    self.init(_storage: storage)
    assert(self._capacity == capacity)
    assert(self._startSlot == startSlot.position)
    assert(self.count == contents.count)
  }

@inlinable
  internal static func allocateCollision<R>(
    count: Int,
    _ hash: _Hash,
    extraBytes: Int = 0,
    initializingWith initializer: (UnsafeMutableBufferPointer<Element>) -> R
  ) -> (node: _HashNode, result: R) {
    assert(count >= 2)
    assert(extraBytes >= 0)
    let itemBytes = count * MemoryLayout<Element>.stride
    let hashBytes = MemoryLayout<_Hash>.stride
    let bytes = itemBytes &+ hashBytes
    assert(MemoryLayout<_Hash>.alignment <= MemoryLayout<_RawHashNode>.alignment)
    let storage = Storage.allocate(byteCapacity: bytes &+ extraBytes)
    var node = _HashNode(storage: storage, count: count)
    let result: R = node.update {
      $0.itemMap = _Bitmap(bitPattern: count)
      $0.childMap = $0.itemMap
      assert(bytes <= $0.bytesFree)
      $0.bytesFree &-= bytes

      $0._memory.storeBytes(of: hash, as: _Hash.self)

      let itemStart = ($0._memory + ($0.byteCapacity &- itemBytes))
        .bindMemory(to: Element.self, capacity: count)

      let items = UnsafeMutableBufferPointer(start: itemStart, count: count)
      return initializer(items)
    }
    return (node, result)
  }

@inlinable
  internal func compactMapValues<T>(
    _ level: _HashLevel,
    _ transform: (Value) throws -> T?
  ) rethrows -> _HashNode<Key, T>.Builder {
    return try self.read {
      var result: _HashNode<Key, T>.Builder = .empty(level)

      if isCollisionNode {
        let items = $0.reverseItems
        for i in items.indices {
          if let v = try transform(items[i].value) {
            result.addNewCollision(level, (items[i].key, v), $0.collisionHash)
          }
        }
        return result
      }

      for (bucket, slot) in $0.itemMap {
        let p = $0.itemPtr(at: slot)
        if let v = try transform(p.pointee.value) {
          result.addNewItem(level, (p.pointee.key, v), at: bucket)
        }
      }

      for (bucket, slot) in $0.childMap {
        let branch = try $0[child: slot]
          .compactMapValues(level.descend(), transform)
        result.addNewChildBranch(level, branch, at: bucket)
      }
      return result
    }
  }

@inlinable @inline(never)
  internal func _isDisjointCollision<Value2>(
    _ level: _HashLevel,
    with other: _HashNode<Key, Value2>
  ) -> Bool {
    assert(isCollisionNode)
    if other.isCollisionNode {
      return read { l in
        other.read { r in
          guard l.collisionHash == r.collisionHash else { return true }
          let litems = l.reverseItems
          let ritems = r.reverseItems
          return litems.allSatisfy { li in
            !ritems.contains { ri in li.key == ri.key }
          }
        }
      }
    }
    // `self` is on a compressed path. Try descending down by one level.
    assert(!level.isAtBottom)
    let bucket = self.collisionHash[level]
    return other.read { r in
      if r.childMap.contains(bucket) {
        let slot = r.childMap.slot(of: bucket)
        return isDisjoint(level.descend(), with: r[child: slot])
      }
      if r.itemMap.contains(bucket) {
        let rslot = r.itemMap.slot(of: bucket)
        let p = r.itemPtr(at: rslot)
        let hash = _Hash(p.pointee.key)
        return read { l in
          guard hash == l.collisionHash else { return true }
          return !l.reverseItems.contains { $0.key == p.pointee.key }
        }
      }
      return true
    }
  }

@inlinable
  internal func _removingChild(
    _ level: _HashLevel, at bucket: _Bucket, _ slot: _HashSlot
  ) -> Builder {
    read {
      assert(!$0.isCollisionNode && $0.childMap.contains(bucket))
      let willAtrophy = (
        $0.itemMap.isEmpty
        && $0.childCount == 2
        && $0[child: _HashSlot(1 &- slot.value)].isCollisionNode
      )
      if willAtrophy {
        // Compression
        let child = $0[child: _HashSlot(1 &- slot.value)]
        return .collisionNode(level, child)
      }
      if $0.itemMap.hasExactlyOneMember && $0.childMap.hasExactlyOneMember {
        return .item(level, $0[item: .zero], at: $0.itemMap.first!)
      }
      if $0.hasSingletonChild {
        // Evaporate node
        return .empty(level)
      }

      var node = self.copy()
      _ = node.removeChild(at: bucket, slot)
      node._invariantCheck()
      return .node(level, node)
    }
  }

@inlinable
  internal func _checkInvariants(node: _HeapNode, min: Element?, max: Element?) {
    let value = _storage[node.offset]
    if let min = min {
      precondition(value >= min,
                   "Element \(value) at \(node) is less than min \(min)")
    }
    if let max = max {
      precondition(value <= max,
                   "Element \(value) at \(node) is greater than max \(max)")
    }
    let left = node.leftChild()
    let right = node.rightChild()
    if node.isMinLevel {
      if left.offset < count {
        _checkInvariants(node: left, min: value, max: max)
      }
      if right.offset < count {
        _checkInvariants(node: right, min: value, max: max)
      }
    } else {
      if left.offset < count {
        _checkInvariants(node: left, min: min, max: value)
      }
      if right.offset < count {
        _checkInvariants(node: right, min: min, max: value)
      }
    }
  }

@_effects(releasenone)
  @usableFromInline
  package func index(_ i: Index, offsetBy distance: Int) -> Index {
    precondition(i <= endIndex, "Index out of bounds")
    precondition(i == endIndex || contains(i.value), "Invalid index")
    guard distance != 0 else { return i }
    var remaining = distance.magnitude
    if distance > 0 {
      var (w, b) = i.split
      precondition(w < wordCount, "Index out of bounds")
      if let v = _words[w].subtracting(_Word(upTo: b)).nthElement(&remaining) {
        return Index(word: w, bit: v)
      }
      while true {
        w &+= 1
        guard w < wordCount else { break }
        if let v = _words[w].nthElement(&remaining) {
          return Index(word: w, bit: v)
        }
      }
      precondition(remaining == 0, "Index out of bounds")
      return endIndex
    }

    // distance < 0
    remaining -= 1
    var (w, b) = i.endSplit
    if w < wordCount {
      if let v = _words[w].intersection(_Word(upTo: b)).nthElementFromEnd(&remaining) {
        return Index(word: w, bit: v)
      }
    }
    while true {
      precondition(w > 0, "Index out of bounds")
      w &-= 1
      if let v = _words[w].nthElementFromEnd(&remaining) {
        return Index(word: w, bit: v)
      }
    }
  }

@usableFromInline
  @_effects(releasenone)
  internal mutating func advance() {
    // Advance to next bucket, checking for wraparound condition.
    _currentBucket.offset &+= 1
    if _currentBucket.offset == _hashTable.bucketCount {
      guard !_wrappedAround else {
        // Prevent wasting battery in an infinite loop if a hash table
        // somehow becomes corrupt.
        fatalError("Hash table has no unoccupied buckets")
      }
      _wrappedAround = true
      _currentBucket.offset = 0
    }

    // If we have loaded enough bits, eat them and return.
    if _remainingBitCount >= _scale {
      _currentRawValue = _nextBits & _hashTable.bucketMask
      _nextBits &>>= _scale
      _remainingBitCount -= _scale
      return
    }

    // Load the next batch of bits.
    var word = _hashTable.position(of: _currentBucket).word
    if _remainingBitCount != 0 {
      word = _hashTable.word(after: word)
    }
    let c = (_hashTable.scale == 5 && word == _hashTable.wordCount - 1 ? 32 : 64)
    let w = _hashTable[word: word]
    _currentRawValue = (_nextBits | (w &<< _remainingBitCount)) & _hashTable.bucketMask
    _nextBits = w &>> (_scale - _remainingBitCount)
    _remainingBitCount = c - (_scale - _remainingBitCount)
  }

@inlinable
  public init(from decoder: Decoder) throws {
    // We expect to be encoded as an array of alternating key-value pairs.
    var container = try decoder.unkeyedContainer()

    self.init()
    while !container.isAtEnd {
      let key = try container.decode(Key.self)
      let (index, bucket) = self._keys._find(key)
      guard index == nil else {
        let context = DecodingError.Context(
          codingPath: container.codingPath,
          debugDescription: "Duplicate key at offset \(container.currentIndex - 1)")
        throw DecodingError.dataCorrupted(context)
      }

      guard !container.isAtEnd else {
        throw DecodingError.dataCorrupted(
          DecodingError.Context(
            codingPath: container.codingPath,
            debugDescription: "Unkeyed container reached end before value in key-value pair"
          )
        )
      }
      let value = try container.decode(Value.self)
      _keys._appendNew(key, in: bucket)
      _values.append(value)
    }
    _checkInvariants()
  }

@inlinable
  @discardableResult
  public mutating func replaceElement(
    at index: Int,
    withKey key: Key,
    value: Value
  ) -> Element {
    precondition(index >= 0 && index < count, "Index out of range")

    let (existingIndex, bucket) = _keys._find(key)

    // The new key compares equal to the one already at `index` — replace
    // in place. The hash bucket is unchanged, so no rehash is needed.
    if existingIndex == index {
      let oldKey = _keys.update(key, at: index)
      let oldValue = _values[index]
      _values[index] = value
      _checkInvariants()
      return (oldKey, oldValue)
    }

    precondition(existingIndex == nil, "Duplicate key: '\(key)'")

    // Append the new key-value pair at the end — amortized O(1)
    _keys._appendNew(key, in: bucket)
    _values.append(value)

    // Swap the new element into the target position — O(1)
    _keys.swapAt(index, count - 1)
    _values.swapAt(index, count - 1)

    // Remove the old element from the end — O(1)
    let oldKey = _keys.removeLast()
    let oldValue = _values.removeLast()

    _checkInvariants()
    return (oldKey, oldValue)
  }

@inlinable
  public mutating func _partition(
    by belongsInSecondPartition: (Element) throws -> Bool,
    callback: (Int, Int) -> Void
  ) rethrows -> Int {
    guard _table != nil else {
      return try _elements.partition(by: belongsInSecondPartition)
    }
    _ensureUnique()
    let result: Int = try _table!.update { hashTable in
      let maybeOffset: Int? = try _elements.withContiguousMutableStorageIfAvailable { buffer in
        let pivot = try buffer._partition(
          with: hashTable,
          by: belongsInSecondPartition,
          callback: callback)
        return pivot - buffer.startIndex
      }
      if let offset = maybeOffset {
        return _elements.index(startIndex, offsetBy: offset)
      }
      return try _elements._partition(
        with: hashTable,
        by: belongsInSecondPartition,
        callback: callback)
    }
    _checkInvariants()
    return result
  }

@inlinable
  internal mutating func _halfStablePartition<Value>(
    values: UnsafeMutableBufferPointer<Value>,
    by belongsInSecondPartition: ((key: Element, value: Value)) throws -> Bool
  ) rethrows -> Int {
    precondition(self.count == values.count)
    var i = 0
    try _elements.withUnsafeMutableBufferPointer { keys in
      while i < keys.count, try !belongsInSecondPartition((keys[i], values[i])) {
        i += 1
      }
    }
    guard i < self.count else { return self.count }

    self._ensureUnique()
    let table = _table
    self._table = nil
    defer { self._table = table }

    return try _elements.withUnsafeMutableBufferPointer { keys in
      for j in i + 1 ..< keys.count {
        guard try !belongsInSecondPartition((keys[j], values[j])) else {
          continue
        }
        keys.swapAt(i, j)
        values.swapAt(i, j)
        table?.update { hashTable in
          hashTable.swapBucketValues(for: keys[i], withCurrentValue: j,
                                     and: keys[j], withCurrentValue: i)
        }
        i += 1
      }
      return i
    }
  }

func _distance(
  from start: Index,
  to end: Index,
  in metric: some _StringMetric
) -> Int {
  precondition(start <= endIndex && end <= endIndex, "Invalid index")
  guard start != end else { return 0 }
  assert(!isEmpty)
  let (lesser, greater) = (start <= end ? (start, end) : (end, start))
  let a = resolve(lesser, preferEnd: false)
  let b = resolve(greater, preferEnd: false)

  let ropeIndexA = a._rope!
  let ropeIndexB = b._rope!
  let chunkIndexA = a._chunkIndex
  let chunkIndexB = b._chunkIndex
  assert(ropeIndexA != _rope.endIndex) // Handled above

  var d = 0
  if ropeIndexA == ropeIndexB {
    d = metric.distance(from: chunkIndexA, to: chunkIndexB, in: _rope[ropeIndexA])
  } else {
    d = _rope.distance(from: ropeIndexA, to: ropeIndexB, in: metric)
    d -= metric.prefixSize(to: chunkIndexA, in: _rope[ropeIndexA])
    if ropeIndexB != _rope.endIndex {
      d += metric.prefixSize(to: chunkIndexB, in: _rope[ropeIndexB])
    }
  }
  return start <= end ? d : -d
}

mutating func resyncBreaksToEnd(
  old: inout _CharacterRecognizer,
  new: inout _CharacterRecognizer
) {
  guard let (ropeIndex, chunkIndex) = _resyncBreaks(old: &old, new: &new) else { return }

  let chars = self.summary.characters
  if chars > 0 {
    var i = endIndex
    while i > ropeIndex {
      formIndex(before: &i)
      if self[i].hasBreaks { break }
    }
    if i > ropeIndex || self[i].lastBreak > chunkIndex {
      new = self[i].immediateLastBreakState!
      formIndex(after: &i)
      while i < endIndex {
        let chunk = self[i]
        new.consumePartialCharacter(chunk.utf8Span)
        formIndex(after: &i)
      }
      old = new
      return
    }
  }

  var ri = ropeIndex
  let chunk = self[ri]
  let after = chunk.scalarIndex(after: chunkIndex)
  let suffix = chunk.utf8Span(from: after, to: chunk.endIndex)
  new.consumePartialCharacter(suffix)
  formIndex(after: &ri)
  while ri < endIndex {
    let chunk = self[ri]
    new.consumePartialCharacter(chunk.utf8Span)
    formIndex(after: &ri)
  }
  old = new
}

@inlinable
  internal func distance(
    from start: Index, to end: Index, in metric: some RopeMetric<Element>
  ) -> Int {
    assert(start < end)
    let a = start._path[height]
    let b = end._path[height]
    precondition(a < childCount, "Invalid index")
    precondition(b <= childCount, "Invalid index")
    assert(a <= b)
    if b == childCount {
      precondition(end._isEmpty(below: height), "Invalid index")
      return distanceToEnd(from: start, in: metric)
    }
    if height == 0 {
      assert(a < b)
      return readLeaf { $0.distance(from: a, to: b, in: metric) }
    }
    return readInner {
      let c = $0.children
      if a == b {
        return c[a].distance(from: start, to: end, in: metric)
      }
      var d = c[a].distanceToEnd(from: start, in: metric)
      d += $0.distance(from: a + 1, to: b, in: metric)
      d += c[b].distanceFromStart(to: end, in: metric)
      return d
    }
  }
